import java.util.Scanner;

public class SecureBufferCopy {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Limit the size of the buffer to prevent buffer overflow
        int bufferSize = Math.min(input.length(), 10);
        char[] buffer = new char[bufferSize];

        // Copy user input into buffer with proper bounds checking
        input.getChars(0, bufferSize, buffer, 0);

        // Print the contents of the buffer safely
        System.out.println("Buffer contents: " + new String(buffer));
    }
}

